function [nmbScnOut,scanOut,scnDir] = fScanDirLstPhosV03(mDir,nmbScn,scan,phosN)%% search directory, return number of scan, scan array, scan directory%% [nmbScnOut,scanOut,scnDir] = fScanDirLstPhosV01(nmbScn,scan)%% mDir: mother directory% nmbScn: number of scan to go through% scan: array of scan numbers% phosN: phosphor number%% nmbScnOut: number of scan with files% scanOut: array of scan numbers% Written by Kei Nakamura% Created on Wednesday, December 15th 2010.% Modified on Thursday, May 12th 2011% ver.2: for new phosphors 1-3% ver.3: Wednesday, February 29th 2012% new background file name, GCP%% main bodyif phosN==1    dirNam = 'PhosphorScreen';    fileNam = '_PhosphorScreen_';elseif phosN==2    dirNam = 'PhosphorScreen2';    fileNam = '_PhosphorScreen2_';elseif phosN==3    dirNam = 'PhosphorScreen3';    fileNam = '_PhosphorScreen3_';endkk = 0;for jj=1:nmbScn    scanNS = fGet3NmbStringV01(scan(jj));    phsDir = [mDir,'/Scan',scanNS,'/',dirNam];    bgLst = dir([phsDir,'/Scan',scanNS,fileNam,'-*.png']);    % bg list    imgLst = dir([phsDir,'/Scan',scanNS,fileNam,'*.png']);    % image list    datName = [mDir,'/Scan',scanNS,'/ScanDataScan',scanNS,'.txt'];  % data name        bgEx = numel(bgLst)>=1;    imgEx = numel(imgLst)>numel(bgLst); % more than number of BG    datEx = exist(datName, 'file');        if bgEx&&imgEx&&datEx        kk = kk + 1;        scanOut(kk) = scan(jj);        scnDir{kk} = ['Scan',scanNS];    endendnmbScnOut = kk;
